package com.robodynamics.core_traditional_java.service;

public interface MessageService {
    String sendMessage(String to, String message);
}

package com.robodynamics.core_traditional_java.service;

public class EmailService implements MessageService {

    @Override
    public String sendMessage(String to, String message) {
        return "EMAIL SENT to " + to + " | message=" + message;
    }
}

package com.robodynamics.core_traditional_java;

import com.robodynamics.core_traditional_java.service.EmailService;
import com.robodynamics.core_traditional_java.service.MessageService;

public class App {

    public static void main(String[] args) {

        // Tight Coupling: direct object creation
        MessageService service = new EmailService();

        String result = service.sendMessage(
                "student@robodynamics.in",
                "Welcome to Spring Core!"
        );

        System.out.println(result);
    }
}

